// Accept juristicId from JSON body, query string, or raw text.
const body = $json.body ?? {};
const query = $json.query ?? {};
let id = body.juristicId ?? query.juristicId ?? body.id ?? query.id ?? '';
id = String(id).replace(/\D/g, '');
if (!/^\d{13}$/.test(id)) {
  throw new Error('juristicId must be exactly 13 digits. Got: ' + JSON.stringify(id));
}
return [{ json: { juristicId: id } }];

// Shape a compact, useful summary from the raw DBD payload.
const r = $json;
if (!r.ok) {
  return [{ json: { ok: false, error: r.error ?? 'lookup failed' } }];
}
const d = r.data ?? {};
return [{
  json: {
    ok: true,
    juristicId: d.jpNo,
    nameTH: d.jpName,
    nameEN: d.jpNameE,
    type: d.jpType?.jpTypeDesc,
    status: d.jpStatus?.jpStatDesc,
    statusEN: d.jpStatus?.jpStatDescE,
    registeredCapital: d.capAmt,
    businessSize: d.businessSizeCode,
    province: d.locationProvince?.pvDesc,
    district: d.locationAmpur?.ampurDesc,
    address: d.address,
    objectiveTH: d.submitObjType?.objDesc ?? d.setupObjType?.objDesc,
    ageYears: d.jpAge,
    raw: d
  }
}];
